#include <stdio.h>
#include <stdlib.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, M;
        scanf("%lld %lld", &N, &M);
        long long ans = M / 2 + 1;
        printf("%lld\n", ans);
    }
    return 0;
}

